SELECT disk_io_agg_id as id, backend_type, collected_at, delta_reads, delta_writes, avg_read_latency_ms, avg_write_latency_ms, cache_hit_ratio, status FROM disk_io_agg WHERE instance_id = #{instanceId} AND collected_at BETWEEN #{startTime} AND #{endTime}
AND status IN
#{status}
ORDER BY collected_at DESC
